import{_ as i,o as t,c as a,ag as o}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Total Harmonic Distortion (THD)","description":"","frontmatter":{},"headers":[],"relativePath":"en/power-quality/thd.md","filePath":"en/power-quality/thd.md"}'),n={name:"en/power-quality/thd.md"};function r(s,e,l,c,p,d){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="total-harmonic-distortion-thd" tabindex="-1">Total Harmonic Distortion (THD) <a class="header-anchor" href="#total-harmonic-distortion-thd" aria-label="Permalink to &quot;Total Harmonic Distortion (THD)&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Total Harmonic Distortion, or THD, is a measure of how much a waveform is distorted by harmonics compared to the fundamental frequency.</p><p>It is commonly used to quantify the quality of voltage or current waveforms in a power system.</p><p>A higher THD value indicates greater distortion and lower power quality.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The purpose of THD is to:</p><ul><li>Evaluate the level of waveform distortion in the system</li><li>Identify potential power quality issues</li><li>Support design and selection of mitigation solutions</li><li>Ensure compliance with acceptable distortion limits</li></ul><p>THD provides a simple way to assess the impact of harmonics.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>THD is calculated as the ratio of the sum of all harmonic components to the fundamental component.</p><p>It is typically expressed as a percentage.</p><p>Two common forms are used:</p><ul><li>Voltage THD</li><li>Current THD</li></ul><p>A low THD value indicates a waveform close to a pure sine wave.</p><p>A high THD value indicates significant distortion caused by harmonic components.</p><p>THD depends on:</p><ul><li>The number and magnitude of harmonic frequencies present</li><li>The type of loads connected to the system</li><li>The impedance of the electrical network</li></ul><h2 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h2><p>THD is used in:</p><ul><li>Power quality monitoring and analysis</li><li>Evaluation of systems with nonlinear loads</li><li>Design and verification of harmonic mitigation solutions</li><li>Industrial facilities with drives, converters, and electronic equipment</li><li>Compliance with power quality standards</li></ul><p>It is a key parameter in modern power systems.</p><h2 id="key-considerations" tabindex="-1">Key Considerations <a class="header-anchor" href="#key-considerations" aria-label="Permalink to &quot;Key Considerations&quot;">​</a></h2><ul><li><p><strong>Acceptable limits</strong><br> Voltage THD is usually kept within defined limits for proper operation</p></li><li><p><strong>Load type</strong><br> Nonlinear loads increase current distortion and can affect voltage THD</p></li><li><p><strong>System strength</strong><br> Strong systems are less affected by harmonic currents</p></li><li><p><strong>Measurement location</strong><br> THD values vary depending on where they are measured</p></li><li><p><strong>Impact on equipment</strong><br> High THD can cause overheating, losses, and malfunction</p></li><li><p><strong>Mitigation methods</strong><br> Filters and system design improvements help reduce THD</p></li></ul><h2 id="practical-notes" tabindex="-1">Practical Notes <a class="header-anchor" href="#practical-notes" aria-label="Permalink to &quot;Practical Notes&quot;">​</a></h2><ul><li>Low current THD does not always guarantee low voltage THD</li><li>High THD levels can lead to overheating of transformers and cables</li><li>Monitoring THD over time helps detect changes in system behavior</li><li>Adding nonlinear loads without analysis can degrade power quality</li><li>Mitigation should focus on the main sources of distortion</li></ul>',26)])])}const m=i(n,[["render",r]]);export{u as __pageData,m as default};
